		if(idx >= hash_bins) idx = hash_bins - 1;
	}

	for( int j = 0; j < num_nucs[mat]; j++ )
	{
		double xs_vector[5];
		p_nuc = mats[mat*max_num_nucs + j];
		conc = concs[mat*max_num_nucs + j];
		calculate_micro_xs_kernel( p_energy, p_nuc, n_isotopes,
		                    n_gridpoints, egrid, index_data,
		                    nuclide_grids, idx, xs_vector, grid_type, hash_bins );
		for( int k = 0; k < 5; k++ )
			macro_xs_vector[k] += xs_vector[k] * conc;
	}
}

kernel void macro_xs_lookup_kernel(Inputs in, int max_num_nucs, 
                                   const int * num_nucs,
                                   const double * concs,
                                   const double * unionized_energy_array,
                                   const int * index_grid,
                                   const NuclideGridPoint * nuclide_grid,
                                   const int * mats,
                                   int * verification_array)
{
	int i = get_global_id(0);

	if(i >= in.lookups) return;

	uint64_t seed = 1070ULL;
	const uint64_t m = 9223372036854775808ULL; 
	const uint64_t a = 2806196910506780709ULL;
	const uint64_t c = 1ULL;

	uint64_t n = 2ULL * (uint64_t)i;
	uint64_t a_new = 1;
	uint64_t c_new = 0;
	uint64_t temp_a = a;
	uint64_t temp_c = c;

	while(n > 0) 
	{
		if(n & 1)
		{
			a_new *= temp_a;
			c_new = c_new * temp_a + temp_c;
		}
		temp_c *= (temp_a + 1);
		temp_a *= temp_a;
		n >>= 1;
	}
	seed = (a_new * seed + c_new) % m;

	double p_energy = (double)seed / (double)m;

	seed = (a * seed + c) % m;
	double roll = (double)seed / (double)m;

	int mat = 0;
	double dist[12];
	dist[0]  = 0.140;	
	dist[1]  = 0.052;	
	dist[2]  = 0.275;	
	dist[3]  = 0.134;	
	dist[4]  = 0.154;	
	dist[5]  = 0.064;	
	dist[6]  = 0.066;	
	dist[7]  = 0.055;	
	dist[8]  = 0.008;	
	dist[9]  = 0.015;	
	dist[10] = 0.025;	
	dist[11] = 0.013;	

	for( int k = 0; k < 12; k++ )
	{
		double running = 0.0;
		for( int j = k; j > 0; j-- )
			running += dist[j];
		if( roll < running )
		{
			mat = k;
			break;
		}
	}

	double macro_xs_vector[5];
	calculate_macro_xs_kernel(
			p_energy,        
			mat,             
			in.n_isotopes,   
			in.n_gridpoints, 
			num_nucs,     
			concs,        
			unionized_energy_array, 
			index_grid,   
			nuclide_grid, 
			mats,         
			macro_xs_vector, 
			in.grid_type,    
			in.hash_bins,    
			max_num_nucs  
			);

	double max = -1.0;
	int max_idx = 0;
	for(int j = 0; j < 5; j++ )
	{
		if( macro_xs_vector[j] > max )
		{
			max = macro_xs_vector[j];
			max_idx = j;
		}
	}

	verification_array[i] = max_idx + 1;
}
